    key: workflowKey,
    steps: [
      {
        command: 'broadcast',
        input: {
          title: 'Welcome!',
        },
      },
      {
        command: 'wait',
        input: {
          duration: 60,
        },
      },
      {
        command: 'broadcast',
        input: {
          title: 'Follow up',
        },
      },
    ],
  };

  const response = await client.workflows.saveWorkflow(workflow);
  console.log(`Workflow '${workflowKey}' created successfully.`);
}

main().catch((err) => {
